const root = document.getElementById('app-root');
const toastRegion = document.getElementById('toast-region');

const PLANS = {
  free:{id:'free',name:'Free',monthly:0,yearly:0,credits:5,desc:'Try Ascend and launch one project.',features:['1 website project','5 AI generations / month','Save up to 5 content pieces','Basic analytics','Community support']},
  starter:{id:'starter',name:'Starter',monthly:30,yearly:300,credits:50,desc:'For solo operators getting consistent.',features:['Everything in Free','50 AI generations / month','3 websites','Social drafts & scheduling','Email support']},
  growth:{id:'growth',name:'Growth',monthly:50,yearly:500,credits:150,desc:'For businesses scaling their marketing.',features:['Everything in Starter','150 AI generations / month','10 websites','Ad campaign management','Analytics dashboard','Priority email support']},
  pro:{id:'pro',name:'Pro',monthly:90,yearly:900,credits:500,recommended:true,desc:'The full growth system for established teams.',features:['Everything in Growth','500 AI generations / month','25 websites','Built-in CRM','Advanced automations','Priority support']},
  scale:{id:'scale',name:'Scale',monthly:160,yearly:1600,credits:null,desc:'Unlimited scale for agencies and teams.',features:['Everything in Pro','Unlimited AI generations','Unlimited websites','Team members','White-label options','API access','Dedicated support']}
};

const NAV = [
  ['dashboard','⌂','Dashboard'],['websites','◇','Websites'],['content','✦','Content'],['social','◎','Social Media'],
  ['ads','◈','Ads'],['assistant','✧','AI Assistant'],['analytics','⌁','Analytics'],['billing','▣','Billing'],['settings','⚙','Settings']
];

const state = {
  session:null, loading:true, interval:localStorage.getItem('ascend-billing')==='yearly'?'yearly':'monthly',
  onboardStep:1, onboardData:{goals:[],socials:[]}, settingsTab:'profile', mobileMenu:false
};

function esc(value){return String(value??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));}
function money(value){return new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(value||0);}
function initials(user){return ((user?.firstName?.[0]||'A')+(user?.lastName?.[0]||'')).toUpperCase();}
function plan(id){return PLANS[id]||PLANS.free;}
function qs(name){return new URLSearchParams(location.search).get(name)||'';}
function route(){return location.pathname.replace(/\/+$/,'')||'/';}
function toast(message,type=''){const el=document.createElement('div');el.className='toast '+type;el.textContent=message;toastRegion.appendChild(el);setTimeout(()=>el.remove(),3600);}
function setBusy(button,busy,label){if(!button)return;if(!button.dataset.label)button.dataset.label=button.textContent;button.disabled=busy;button.textContent=busy?(label||'Working…'):button.dataset.label;}

async function api(url,options={}){
  const response=await fetch(url,{...options,headers:{'Content-Type':'application/json',...(options.headers||{})}});
  const data=await response.json().catch(()=>({}));
  if(!response.ok){const error=new Error(data.error||'Request failed');error.code=data.code;error.data=data;throw error;}
  return data;
}

function brand(){return `<a class="brand" href="/"><span class="brand-icon">A</span><span>Ascend<small>Growth platform</small></span></a>`;}
function publicNav(){return `<header class="topnav">${brand()}<nav class="nav-links"><a href="/#platform">Platform</a><a href="/pricing">Pricing</a><a href="/#solutions">Solutions</a></nav><div class="nav-actions">${state.session?'<a class="btn btn-ghost" href="/app">Open workspace</a>':'<a class="btn btn-ghost" href="/login">Log in</a><a class="btn btn-primary" href="/signup">Start free</a>'}</div></header>`;}
function footer(){return `<footer class="public-footer"><div class="footer-inner">${brand()}<span>© ${new Date().getFullYear()} Ascend. Built for modern growth teams.</span><span><a href="/pricing">Pricing</a> · Privacy · Terms</span></div></footer>`;}

function renderLanding(){
  document.title='Ascend — Your growth command center';
  return `<div class="public-shell">${publicNav()}<main>
  <section class="hero"><div><span class="eyebrow"><i class="pulse-dot"></i> One workspace. Every growth channel.</span><h1>Build, market, and grow from <span class="gradient-text">one command center.</span></h1><p class="hero-copy">Ascend brings websites, content, social scheduling, advertising, AI, CRM, and analytics into one focused workspace built for service businesses.</p><div class="hero-actions"><a href="/signup" class="btn btn-primary btn-lg">Start building free <span>→</span></a><a href="/pricing" class="btn btn-lg">Explore plans</a></div><div class="trust-row"><span><b class="check">✓</b>No card required</span><span><b class="check">✓</b>Guided setup</span><span><b class="check">✓</b>Cancel anytime</span></div></div>
  <div class="product-window"><div class="window-bar"><i></i><i></i><i></i><small>ASCEND WORKSPACE · LIVE</small></div><div class="window-grid"><div class="mini-side"><b></b><span></span><span></span><span></span><span></span><span></span></div><div class="mini-main"><div class="mini-stats"><div class="mini-card"><small>CAMPAIGN REACH</small><strong>12.8k</strong><em></em></div><div class="mini-card"><small>AI WORKFLOWS</small><strong>24</strong><em></em></div><div class="mini-card"><small>CONVERSION</small><strong>8.4%</strong><em></em></div></div><div class="mini-chart">${[38,51,44,68,57,79,72,92,84,100].map(h=>`<span style="--h:${h}%"></span>`).join('')}</div><div class="mini-list"><i></i><i></i><i></i></div></div></div><span class="float-pill one"><b>+24%</b> campaign performance</span><span class="float-pill two"><b>3 posts</b> ready to schedule</span></div></section>
  <div class="logo-strip">A focused operating system for websites · content · social · ads · analytics</div>
  <section class="feature-section" id="platform"><div class="section-head"><span class="eyebrow">Everything connected</span><h2>Less tool switching. More momentum.</h2><p>Move from idea to execution without losing context across a pile of disconnected software.</p></div><div class="feature-grid">${[
    ['◫','Websites','Create and manage polished web experiences from one organized project library.'],['✦','Content studio','Turn focused briefs into campaign-ready posts, Reels, and creative directions.'],['◎','Social scheduling','Plan your calendar, connect channels, and keep publishing consistent.'],['◈','Ad management','Prepare campaigns, creative, budgets, and reporting in a single view.'],['✧','AI assistance','Use one context-aware assistant across your company, brand, and goals.'],['⌁','Unified analytics','Understand what is working across channels without rebuilding reports.']
  ].map(x=>`<article class="feature-card"><div class="feature-icon">${x[0]}</div><h3>${x[1]}</h3><p>${x[2]}</p></article>`).join('')}</div></section>
  <section class="pricing-section" id="solutions"><div class="section-head"><span class="eyebrow">Simple plans</span><h2>Start free. Scale when it works.</h2><p>Choose the workspace that matches the way your business operates today.</p></div>${pricingBlock(true)}</section>
  </main>${footer()}</div>`;
}

function authAside(){return `<aside class="auth-aside"><div class="auth-aside-inner"><div class="auth-visual"><div class="auth-bars">${[28,42,37,61,55,78,70,91,84].map(h=>`<i style="--h:${h}%"></i>`).join('')}</div></div><div class="auth-quote">Your business deserves a system that keeps up with your ambition.</div><div class="auth-caption">Websites, content, campaigns, and intelligence—working together.</div></div></aside>`;}
function inputField(label,id,type='text',placeholder='',extra=''){return `<div class="field"><label for="${id}">${label}${extra}</label>${type==='password'?`<div class="password-wrap"><input class="input" id="${id}" name="${id}" type="password" placeholder="${placeholder}" required><button class="password-toggle" type="button" data-password="${id}" aria-label="Show password">◉</button></div>`:`<input class="input" id="${id}" name="${id}" type="${type}" placeholder="${placeholder}" required>`}</div>`;}
function authLayout(content){return `<div class="auth-wrap"><main class="auth-panel">${brand()}<div class="auth-card">${content}</div><div class="legal">By continuing, you agree to Ascend's Terms and acknowledge the Privacy Policy.</div></main>${authAside()}</div>`;}
function renderLogin(){document.title='Log in — Ascend';return authLayout(`<span class="eyebrow">Welcome back</span><h1>Log in to Ascend</h1><p>Continue building from your customer workspace.</p><form id="login-form">${inputField('Work email','email','email','you@company.com')}${inputField('Password','password','password','Your password','<a href="/forgot-password">Forgot password?</a>')}<button class="btn btn-primary btn-block btn-lg" type="submit">Log in</button><div class="form-status" id="form-status"></div></form><div class="auth-switch">New to Ascend? <a href="/signup">Create an account</a></div>`);}
function renderSignup(){document.title='Create your account — Ascend';return authLayout(`<span class="eyebrow">Start free</span><h1>Create your workspace</h1><p>Set up your account now. Choose a plan after email verification.</p><form id="signup-form"><div class="field-row">${inputField('First name','firstName','text','Ty')}${inputField('Last name','lastName','text','Smith')}</div>${inputField('Work email','email','email','you@company.com')}${inputField('Password','password','password','10+ characters')}<div class="form-note">Use at least 10 characters with uppercase, lowercase, and a number.</div><button class="btn btn-primary btn-block btn-lg" type="submit">Create account</button><div class="form-status" id="form-status"></div></form><div class="auth-switch">Already have an account? <a href="/login">Log in</a></div>`);}
function renderForgot(){document.title='Reset your password — Ascend';return authLayout(`<div class="mail-visual">↗</div><h1>Reset your password</h1><p>Enter your account email and we’ll send a secure reset link.</p><form id="forgot-form">${inputField('Work email','email','email','you@company.com')}<button class="btn btn-primary btn-block btn-lg" type="submit">Send reset link</button><div class="form-status" id="form-status"></div></form><div class="auth-switch"><a href="/login">← Back to login</a></div>`);}
function renderVerify(){document.title='Verify your email — Ascend';const token=qs('token'),failed=qs('delivery')==='failed';return authLayout(`<div class="mail-visual">${failed?'!':'✓'}</div><h1>${token?'Verifying your email':failed?'Let’s resend your email':'Check your inbox'}</h1><p>${token?'We’re securely confirming your account.':failed?'Your account was created, but the first verification message could not be delivered. Use the button below to send it again.':'Open the verification link we sent to finish creating your workspace.'}</p><div id="verify-state" class="form-status ${failed?'error':''}">${token?'Please wait…':failed?'Verification email delivery failed. Your account is safe—resend it now.':'The link expires in 24 hours.'}</div>${token?'':'<form id="resend-form">'+inputField('Email','email','email','you@company.com')+'<button class="btn btn-primary btn-block" type="submit">Resend verification</button></form>'}<div class="auth-switch"><a href="/login">Return to login</a></div>`);}
function renderReset(){document.title='Choose a new password — Ascend';return authLayout(`<div class="mail-visual">⌁</div><h1>Choose a new password</h1><p>Create a strong password you haven’t used for this account before.</p><form id="reset-form">${inputField('New password','password','password','10+ characters')}${inputField('Confirm password','confirmPassword','password','Repeat password')}<button class="btn btn-primary btn-block btn-lg" type="submit">Update password</button><div class="form-status" id="form-status"></div></form>`);}

function pricingBlock(compact=false){return `<div class="billing-toggle"><button data-interval="monthly" class="${state.interval==='monthly'?'active':''}">Monthly</button><button data-interval="yearly" class="${state.interval==='yearly'?'active':''}">Yearly <span class="save-badge">SAVE ~17%</span></button></div><div class="pricing-grid">${Object.values(PLANS).map(p=>priceCard(p,compact)).join('')}</div>`;}
function priceCard(p){const amount=state.interval==='yearly'?p.yearly:p.monthly;const unit=state.interval==='yearly'?'/year':'/month';const monthly=state.interval==='yearly'&&amount?`Equivalent to ${money(Math.round(amount/12))}/month`:(p.id==='free'?'Free forever':'Billed monthly');return `<article class="price-card ${p.recommended?'recommended':''}">${p.recommended?'<span class="recommend-badge">RECOMMENDED</span>':''}<div class="price-name">${p.name}</div><div class="price-desc">${p.desc}</div><div class="price">${money(amount)}<small>${p.id==='free'?'':unit}</small></div><div class="price-note">${monthly}</div><a class="btn ${p.recommended?'btn-primary':''}" href="${checkoutLink(p.id)}">${p.id==='free'?'Start free':state.session?'Choose '+p.name:'Get started'}</a><ul class="feature-list">${p.features.map(f=>`<li>${f}</li>`).join('')}</ul></article>`;}
function checkoutLink(planId){if(!state.session)return `/signup?plan=${planId}&interval=${state.interval}`;if(planId==='free')return state.session.user?.onboarding?.completed?'/app':'/welcome';return `/checkout?plan=${planId}&interval=${state.interval}`;}
function renderPricing(){document.title='Pricing — Ascend';return `<div class="pricing-page">${publicNav()}<section class="pricing-section"><div class="section-head"><span class="eyebrow">Clear, flexible pricing</span><h2>A plan for every stage of growth.</h2><p>Start with the essentials, then unlock the complete operating system as your business grows.</p></div>${pricingBlock()}</section>${footer()}</div>`;}

function selectedCheckout(){const id=qs('plan')||sessionStorage.getItem('ascend-plan')||'growth';const interval=qs('interval')||sessionStorage.getItem('ascend-interval')||state.interval;const chosen=plan(id);sessionStorage.setItem('ascend-plan',chosen.id);sessionStorage.setItem('ascend-interval',interval);return {chosen,interval,amount:interval==='yearly'?chosen.yearly:chosen.monthly};}
function checkoutSteps(active){return `<div class="checkout-steps">${['Review','Payment','Complete'].map((x,i)=>`${i?'<span class="checkout-line"></span>':''}<span class="checkout-step ${i<active?'done':i===active?'active':''}"><i>${i<active?'✓':i+1}</i>${x}</span>`).join('')}</div>`;}
function orderSummary(data,button=''){return `<aside class="checkout-card order-summary"><span class="plan-pill">${data.chosen.name} plan</span><div class="summary-price">${money(data.amount)}<small>/${data.interval==='yearly'?'year':'month'}</small></div><p>${data.chosen.desc}</p><ul class="feature-list">${data.chosen.features.slice(0,6).map(x=>`<li>${x}</li>`).join('')}</ul><div class="summary-total"><span>Due today</span><strong>${state.session?.stripeConfigured?money(data.amount):'$0'}</strong></div>${button}</aside>`;}
function renderCheckout(){document.title='Review your plan — Ascend';const data=selectedCheckout();return `<div class="checkout-wrap">${publicNav()}<main class="checkout-main">${checkoutSteps(0)}<div class="checkout-grid"><section class="checkout-card"><span class="eyebrow">Plan review</span><h1>Confirm your selection</h1><p>Review your plan and billing cadence before continuing to secure payment.</p><div class="review-list"><div class="review-row"><span>Plan</span><strong>${data.chosen.name}</strong></div><div class="review-row"><span>Billing</span><strong>${data.interval==='yearly'?'Annual':'Monthly'}</strong></div><div class="review-row"><span>Renewal</span><strong>Automatic until canceled</strong></div><div class="review-row"><span>Trial</span><strong>14 days</strong></div></div><div style="display:flex;gap:9px;margin-top:25px"><a class="btn" href="/pricing">Change plan</a><a class="btn btn-primary" href="/checkout/payment?plan=${data.chosen.id}&interval=${data.interval}">Continue to payment →</a></div></section>${orderSummary(data)}</div></main></div>`;}
function renderPayment(){document.title='Payment — Ascend';const data=selectedCheckout();const demo=!state.session?.stripeConfigured;return `<div class="checkout-wrap">${publicNav()}<main class="checkout-main">${checkoutSteps(1)}<div class="checkout-grid"><section class="checkout-card"><span class="eyebrow">Secure checkout</span><h1>${demo?'Preview payment flow':'Payment details'}</h1><p>${demo?'Stripe is not connected yet. This screen demonstrates the complete handoff and starts a no-charge demo trial.':'Enter your payment details securely through Stripe.'}</p>${demo?'<div class="demo-banner"><b>DEMO CHECKOUT</b><br>No card will be charged. A trialing subscription record will be created so you can test the customer experience.</div>':''}<div class="field"><label>Name on card</label><input class="input" placeholder="Ty Smith" ${demo?'disabled':''}></div><div class="field"><label>Card information</label><div class="card-mock"><div class="card-fields"><input class="input" placeholder="1234 1234 1234 1234" disabled><input class="input" placeholder="MM / YY" disabled><input class="input" placeholder="CVC" disabled></div></div></div><div class="field"><label>Billing country</label><select class="select" ${demo?'disabled':''}><option>United States</option></select></div><button id="activate-plan" class="btn btn-primary btn-block btn-lg">${demo?'Start demo trial':'Subscribe securely'}</button><div class="form-status" id="form-status"></div></section>${orderSummary(data)}</div></main></div>`;}
function renderSuccess(){document.title='Subscription active — Ascend';const p=plan(state.session?.user?.subscription?.plan);return `<div class="checkout-wrap">${publicNav()}<main class="checkout-main">${checkoutSteps(2)}<section class="checkout-card success-card"><div class="success-icon">✓</div><span class="eyebrow">Setup complete</span><h1>Your ${p.name} workspace is ready.</h1><p>${state.session?.user?.subscription?.billingMode==='demo'?'Your no-charge demo subscription is active. Connect Stripe before accepting real customer payments.':'Your subscription is active and your workspace limits have been updated.'}</p><a class="btn btn-primary btn-lg" href="${state.session?.user?.onboarding?.completed?'/app':'/welcome'}">Continue to workspace →</a></section></main></div>`;}

const ONBOARD_STEPS=[
  ['Company name','What should we call your workspace?'],['Industry','Help Ascend tailor recommendations.'],['Website','Connect your current online home.'],['Brand colors','Set the visual foundation for generated work.'],['Logo','Give your workspace a recognizable identity.'],['Goals','Choose what you want to accomplish first.'],['Social accounts','Prepare your channels for future connections.'],['Ready to build','Review the foundation of your workspace.']
];
function renderWelcome(){document.title='Set up your workspace — Ascend';const stored=state.session?.user?.onboarding||{};if(!state.onboardInitialized){state.onboardStep=Math.max(1,Math.min(8,stored.step||1));state.onboardData={goals:[],socials:[],...(stored.data||{})};state.onboardInitialized=true;}const meta=ONBOARD_STEPS[state.onboardStep-1];return `<div class="onboarding-shell"><aside class="onboarding-side">${brand()}<h2>Build your foundation.</h2><p>Ascend uses this information to personalize your workspace, content, and recommendations.</p><div class="progress-track"><i style="--progress:${state.onboardStep/8*100}%"></i></div><div class="step-label">Step ${state.onboardStep} of 8 · ${meta[0]}</div></aside><main class="onboarding-main"><section class="onboarding-card"><span class="step-kicker">Step ${state.onboardStep} of 8</span><h1>${meta[0]}</h1><p>${meta[1]}</p>${onboardStepContent()}<div class="onboard-actions">${state.onboardStep>1?'<button class="btn" id="onboard-back">← Back</button>':'<span></span>'}<button class="btn btn-primary btn-lg" id="onboard-next">${state.onboardStep===8?'Finish setup':'Continue →'}</button></div><div class="form-status" id="form-status"></div></section></main></div>`;}
function onboardStepContent(){const d=state.onboardData;switch(state.onboardStep){
  case 1:return `<div class="field"><label>Company or brand name</label><input id="onboard-value" class="input" value="${esc(d.companyName||'')}" placeholder="Ascend Web Development" autofocus></div>`;
  case 2:return `<div class="field"><label>Industry</label><select id="onboard-value" class="select"><option value="">Select an industry</option>${['Agency','Professional services','Home services','Health & wellness','Real estate','E-commerce','Software','Education','Other'].map(x=>`<option ${d.industry===x?'selected':''}>${x}</option>`).join('')}</select></div>`;
  case 3:return `<div class="field"><label>Website URL <span>Optional</span></label><input id="onboard-value" class="input" value="${esc(d.websiteUrl||'')}" placeholder="yourcompany.com"></div><div class="notice">No website yet? Skip this step and create one from your workspace later.</div>`;
  case 4:return `<div class="color-grid"><div class="color-field"><label>Primary color</label><input id="primaryColor" type="color" value="${esc(d.primaryColor||'#66f2a3')}"></div><div class="color-field"><label>Secondary color</label><input id="secondaryColor" type="color" value="${esc(d.secondaryColor||'#5de6e6')}"></div></div>`;
  case 5:return `<label class="upload-zone" for="logo-upload">${d.logoData?`<img class="upload-preview" src="${d.logoData}" alt="Uploaded logo"><b>Logo ready</b><br><small>Click to replace it</small>`:'<div class="empty-icon">↥</div><b>Upload your logo</b><br><small>PNG, JPG, or WebP · under 350 KB</small>'}<input id="logo-upload" type="file" accept="image/png,image/jpeg,image/webp" hidden></label>`;
  case 6:return `<div class="choice-grid">${['Get more customers','Launch a better website','Create consistent content','Run profitable ads','Save time with AI','Understand performance'].map(x=>`<button class="choice ${(d.goals||[]).includes(x)?'active':''}" data-goal="${esc(x)}">${x}</button>`).join('')}</div>`;
  case 7:return `<div class="social-row">${['Instagram','Facebook','LinkedIn','TikTok','YouTube','X'].map(x=>`<button class="social-chip ${(d.socials||[]).includes(x)?'active':''}" data-social="${x}">${x}</button>`).join('')}</div><div class="notice" style="margin-top:18px">Connections are placeholders for now. You can finish secure OAuth setup from Social Media later.</div>`;
  default:return `<div class="glass-card panel"><div class="review-row"><span>Workspace</span><strong>${esc(d.companyName||'Your company')}</strong></div><div class="review-row"><span>Industry</span><strong>${esc(d.industry||'Not selected')}</strong></div><div class="review-row"><span>Website</span><strong>${esc(d.websiteUrl||'Create later')}</strong></div><div class="review-row"><span>Goals selected</span><strong>${(d.goals||[]).length}</strong></div></div>`;
}}

function sectionFromHash(){const key=location.hash.replace('#','');return NAV.some(x=>x[0]===key)?key:'dashboard';}
function appShell(){const section=sectionFromHash(),user=state.session.user,workspace=user.companyName||user.onboarding?.data?.companyName||'My workspace';return `<div class="customer-shell ${state.mobileMenu?'menu-open':''}" id="customer-shell"><aside class="sidebar">${brand()}<div class="workspace-switch"><span class="workspace-logo">${esc(workspace[0]||'A')}</span><span><b>${esc(workspace)}</b><small>${esc(plan(user.subscription?.plan).name)} workspace</small></span></div><div class="side-label">Workspace</div><nav class="side-nav">${NAV.slice(0,7).map(x=>sideLink(x,section)).join('')}</nav><div class="sidebar-bottom"><div class="side-label">Account</div><nav class="side-nav">${NAV.slice(7).map(x=>sideLink(x,section)).join('')}</nav><div class="user-mini"><span class="avatar">${initials(user)}</span><span><b>${esc(user.firstName+' '+user.lastName)}</b><small>${esc(user.email)}</small></span><button class="logout-icon" id="logout-btn" title="Log out">↗</button></div></div></aside><main class="main-area"><header class="app-topbar"><div style="display:flex;align-items:center;gap:11px"><button class="icon-btn mobile-menu" id="mobile-menu">☰</button><div class="page-title"><h1>${NAV.find(x=>x[0]===section)?.[2]||'Dashboard'}</h1><p>${sectionSubtitle(section)}</p></div></div><div class="top-actions"><a class="btn btn-primary" href="#assistant">✦ Ask Ascend</a><button class="icon-btn">⌕</button><button class="icon-btn">♢<i></i></button></div></header><div class="app-content">${renderAppSection(section)}</div></main></div>`;}
function sideLink(item,current){return `<a class="side-link ${item[0]===current?'active':''}" href="#${item[0]}"><span class="side-icon">${item[1]}</span>${item[2]}</a>`;}
function sectionSubtitle(s){return ({dashboard:'Your business at a glance',websites:'Build and manage your online presence',content:'Create campaign-ready content',social:'Plan and publish across channels',ads:'Launch and optimize paid campaigns',assistant:'Work with your context-aware AI',analytics:'See what is moving the business',billing:'Manage plans and payments',settings:'Control your account and workspace'}[s]||'');}
function renderAppSection(section){switch(section){case'websites':return modulePage('Websites','Create Website','◇','Your website library is ready','Create and manage conversion-focused websites for your business.','New website');case'content':return modulePage('Content Studio','Generate Content','✦','Turn your first idea into a campaign','Generate posts, Reels, captions, and creative direction using your brand context.','Generate content');case'social':return modulePage('Social Media','Connect Account','◎','Connect your first social channel','Schedule posts and manage publishing once your social accounts are connected.','Connect account');case'ads':return modulePage('Ad Campaigns','Launch Campaign','◈','Launch your first campaign','Build campaign briefs, organize creative, and track performance from one place.','Create campaign');case'assistant':return assistantPage();case'analytics':return analyticsPage();case'billing':return billingPage();case'settings':return settingsPage();default:return dashboardHome();}}
function dashboardHome(){const u=state.session.user,p=plan(u.subscription?.plan),used=u.usage?.aiUsed||0,remaining=p.credits===null?'Unlimited':Math.max(0,p.credits-used),websites=u.usage?.websites||0;return `<div class="welcome-row"><div><h2>Good ${new Date().getHours()<12?'morning':new Date().getHours()<18?'afternoon':'evening'}, ${esc(u.firstName||'there')}.</h2><p>Here’s what’s happening across ${esc(u.companyName||'your workspace')}.</p></div><a class="btn" href="#settings">Customize workspace</a></div><div class="stat-grid">${stat('Current plan',p.name,u.subscription?.status==='trialing'?'14-day demo trial':'Active','▣')}${stat('AI credits',remaining,p.credits===null?'No generation cap':used+' used this cycle','✦')}${stat('Websites',websites,websites?'Active projects':'Ready to create','◇')}${stat('Campaign performance','—','Connect data to begin','⌁')}</div><div class="dashboard-grid"><section class="glass-card panel"><div class="panel-head"><h3>Performance overview</h3><span>Last 30 days ▾</span></div><div class="chart-wrap"><div class="chart-grid"></div>${[25,33,29,42,38,48,45,55,50,62,58,72].map((h,i)=>`<div class="chart-bar"><i style="--h:${h}%"></i><i class="alt" style="--h:${Math.max(8,h-12+(i%3)*4)}%"></i></div>`).join('')}</div><div class="chart-labels"><span>Week 1</span><span>Week 2</span><span>Week 3</span><span>Week 4</span></div><div class="notice" style="margin-top:17px">Connect websites, social accounts, or ad platforms to replace this preview with live performance data.</div></section><section class="glass-card panel"><div class="panel-head"><h3>Quick actions</h3><span>Start something</span></div><div class="quick-grid">${[['◇','Create Website','websites'],['✦','Generate Content','content'],['◎','Schedule Posts','social'],['◈','Launch Ads','ads']].map(x=>`<a class="quick-action" href="#${x[2]}"><span class="feature-icon">${x[0]}</span><b>${x[1]}</b><small>Open workspace →</small></a>`).join('')}</div></section></div><div class="dashboard-grid"><section class="glass-card panel"><div class="panel-head"><h3>Recent activity</h3><span>View all</span></div><div class="activity-list"><div class="activity-item"><span class="activity-dot">✓</span><span><b>Workspace created</b><p>Your Ascend customer workspace is ready.</p></span><time>Today</time></div>${u.onboarding?.completed?'<div class="activity-item"><span class="activity-dot">✦</span><span><b>Onboarding completed</b><p>Your company profile now powers future recommendations.</p></span><time>Today</time></div>':''}</div></section><section class="glass-card panel"><div class="panel-head"><h3>Recent AI generations</h3><a href="#content">Open studio</a></div><div class="empty-state" style="padding:26px"><div class="empty-icon">✦</div><h3>No generations yet</h3><p>Your latest content and AI work will appear here.</p></div></section></div>`;}
function stat(label,value,sub,icon){return `<article class="glass-card stat-card"><div class="stat-top"><span>${label}</span><span class="stat-icon">${icon}</span></div><div class="stat-value">${esc(value)}</div><div class="stat-sub">${esc(sub)}</div></article>`;}
function workspaceData(){return state.session?.user?.workspace||{websites:[],content:[],socialDrafts:[],campaigns:[],assistant:[]};}
function upgradeCard(title,copy){return `<section class="glass-card" style="margin-top:12px"><div class="empty-state"><div class="empty-icon">↗</div><h3>${title}</h3><p>${copy}</p><a class="btn btn-primary" href="/pricing">View plans</a></div></section>`;}
function modulePage(title,action,icon,emptyTitle,emptyText,button){const kind=sectionFromHash(),w=workspaceData(),p=plan(state.session.user.subscription?.plan);if(kind==='websites'){const sites=w.websites||[];return `<div class="section-toolbar"><div><h2>Websites</h2><p>Build and manage your online presence.</p></div><button class="btn btn-primary" data-workspace-action="website">+ Create Website</button></div>${sites.length?`<div class="module-grid">${sites.map(s=>`<article class="glass-card module-card"><span class="feature-icon">◇</span><h3>${esc(s.name)}</h3><p>${esc(s.url||'No domain added yet')}</p><span class="plan-pill">${esc(s.status)}</span></article>`).join('')}</div>`:`<section class="glass-card"><div class="empty-state"><div class="empty-icon">◇</div><h3>Create your first website project</h3><p>Set up a site name and domain, then keep its work organized in your workspace.</p><button class="btn btn-primary" data-workspace-action="website">Create Website</button></div></section>`}${p.id==='free'?'<div class="notice" style="margin-top:12px">Free includes one website project.</div>':''}`;}if(kind==='content'){const items=w.content||[];return `<div class="section-toolbar"><div><h2>Content Studio</h2><p>Create usable content with your company context.</p></div><button class="btn btn-primary" data-workspace-action="content">+ Generate Content</button></div>${items.length?`<div class="activity-list glass-card panel">${items.map(i=>`<div class="activity-item"><span class="activity-dot">✦</span><span><b>${esc(i.topic)}</b><p>${esc(i.text)}</p></span><time>${new Date(i.createdAt).toLocaleDateString()}</time></div>`).join('')}</div>`:`<section class="glass-card"><div class="empty-state"><div class="empty-icon">✦</div><h3>Turn an idea into content</h3><p>Generate a ready-to-review social post, using one AI credit.</p><button class="btn btn-primary" data-workspace-action="content">Generate Content</button></div></section>`}`;}if(kind==='social'){if(p.id==='free')return `<div class="section-toolbar"><div><h2>Social Media</h2><p>Plan publishing across connected channels.</p></div></div>${upgradeCard('Social scheduling is available on Starter','Upgrade to create drafts, connect supported channels, and schedule publishing.')}`;const drafts=w.socialDrafts||[];return `<div class="section-toolbar"><div><h2>Social Media</h2><p>Save post drafts before publishing.</p></div><button class="btn btn-primary" data-workspace-action="social">+ Create Draft</button></div>${drafts.length?`<div class="activity-list glass-card panel">${drafts.map(d=>`<div class="activity-item"><span class="activity-dot">◎</span><span><b>Post draft</b><p>${esc(d.text)}</p></span><time>${new Date(d.createdAt).toLocaleDateString()}</time></div>`).join('')}</div>`:`<section class="glass-card"><div class="empty-state"><div class="empty-icon">◎</div><h3>Create your first post draft</h3><p>Draft copy here, then publish when your channels are connected.</p><button class="btn btn-primary" data-workspace-action="social">Create Draft</button></div></section>`}`;}if(kind==='ads'){if(!['growth','pro','scale'].includes(p.id))return `<div class="section-toolbar"><div><h2>Ad Campaigns</h2><p>Build campaign briefs and track performance.</p></div></div>${upgradeCard('Ad campaign management starts on Growth','Upgrade to create campaign briefs and organize paid-media work.')}`;const campaigns=w.campaigns||[];return `<div class="section-toolbar"><div><h2>Ad Campaigns</h2><p>Plan your campaign work.</p></div><button class="btn btn-primary" data-workspace-action="campaign">+ Create Campaign</button></div>${campaigns.length?`<div class="module-grid">${campaigns.map(c=>`<article class="glass-card module-card"><span class="feature-icon">◈</span><h3>${esc(c.name)}</h3><p>${esc(c.objective||'No objective set')}</p><span class="plan-pill">${esc(c.status)}</span></article>`).join('')}</div>`:`<section class="glass-card"><div class="empty-state"><div class="empty-icon">◈</div><h3>Launch your first campaign</h3><p>Start with a focused campaign brief.</p><button class="btn btn-primary" data-workspace-action="campaign">Create Campaign</button></div></section>`}`;}return '';}
function assistantPage(){const w=workspaceData(),history=(w.assistant||[]).slice(0,5);return `<div class="section-toolbar"><div><h2>AI Assistant</h2><p>Ask practical questions using your company context.</p></div></div><div class="dashboard-grid"><section class="glass-card panel"><div class="activity-list">${history.length?history.map(x=>`<div class="activity-item"><span class="activity-dot">✧</span><span><b>${esc(x.prompt)}</b><p>${esc(x.answer)}</p></span></div>`).join(''):`<div class="empty-state" style="padding:35px"><div class="empty-icon">✧</div><h3>What are you working on?</h3><p>Ask for a website plan, campaign idea, content brief, or performance explanation.</p></div>`}</div><form id="assistant-form" class="field" style="margin:18px 0 0"><textarea class="input" id="assistant-prompt" placeholder="Ask Ascend anything…" rows="4"></textarea><button class="btn btn-primary" style="margin-top:10px">Ask Ascend</button><div class="form-status" id="form-status"></div></form></section><aside class="glass-card panel"><div class="panel-head"><h3>Workspace context</h3><span>Private</span></div><div class="activity-list"><div class="activity-item"><span class="activity-dot">◇</span><span><b>${esc(state.session.user.companyName||'Company profile')}</b><p>Company and brand context</p></span></div><div class="activity-item"><span class="activity-dot">✦</span><span><b>${(state.session.user.onboarding?.data?.goals||[]).length} goals</b><p>Used to focus recommendations</p></span></div></div></aside></div>`;}
function analyticsPage(){const w=workspaceData();const sites=(w.websites||[]).length,content=(w.content||[]).length,drafts=(w.socialDrafts||[]).length,campaigns=(w.campaigns||[]).length;return `<div class="section-toolbar"><div><h2>Analytics</h2><p>Basic workspace activity for your current plan.</p></div><a class="btn" href="/pricing">Connect live data on Growth</a></div><div class="stat-grid">${stat('Website projects',sites,sites?'Created in workspace':'Create a website','◇')}${stat('Content pieces',content,content?'Generated in workspace':'Generate content','✦')}${stat('Social drafts',drafts,drafts?'Ready to review':'Starter feature','◎')}${stat('Campaign briefs',campaigns,campaigns?'In progress':'Growth feature','◈')}</div><section class="glass-card panel" style="margin-top:12px"><div class="panel-head"><h3>Workspace activity</h3><span>Live</span></div><div class="notice green">This view updates as you create work in Ascend. Connect channel integrations on Growth for traffic, reach, ad spend, and conversion reporting.</div></section>`;}
function billingPage(){const u=state.session.user,p=plan(u.subscription?.plan),s=u.subscription||{};return `<div class="section-toolbar"><div><h2>Billing & subscription</h2><p>Manage your plan, billing cycle, and invoices.</p></div><a href="/pricing" class="btn btn-primary">Compare plans</a></div><section class="glass-card billing-hero"><div><span class="plan-pill">${esc(s.status||'active')}</span><h2>${p.name}</h2><p>${s.billingMode==='demo'?'Demo billing · no payment collected':s.billingMode==='free'?'Free plan · no payment method required':`${esc(s.interval||'monthly')} billing`}${s.cancelAtPeriodEnd?' · Cancels at period end':''}</p></div><div style="display:flex;gap:8px">${s.cancelAtPeriodEnd?'<button class="btn" data-billing="resume">Resume subscription</button>':p.id!=='free'?'<button class="btn" data-billing="cancel">Cancel plan</button>':''}<a href="/pricing" class="btn btn-primary">Change plan</a></div></section><div class="dashboard-grid"><section class="glass-card panel"><div class="panel-head"><h3>Payment method</h3><span>Stripe ready</span></div>${s.billingMode==='demo'||s.billingMode==='free'?'<div class="empty-state" style="padding:30px"><div class="empty-icon">▣</div><h3>No payment method</h3><p>Payment details will be managed securely by Stripe after integration.</p><button class="btn" disabled>Update payment method</button></div>':'<div class="notice">Payment method managed by Stripe.</div>'}</section><section class="glass-card panel"><div class="panel-head"><h3>Next renewal</h3></div><div class="stat-value">${s.currentPeriodEnd?new Date(s.currentPeriodEnd).toLocaleDateString('en-US',{month:'short',day:'numeric'}):'—'}</div><div class="stat-sub">${s.cancelAtPeriodEnd?'Access ends on this date':'Automatic renewal'}</div></section></div><section class="glass-card panel" style="margin-top:12px"><div class="panel-head"><h3>Invoices</h3><span>Download history</span></div>${(u.invoices||[]).length?'<table class="invoice-table"><thead><tr><th>Date</th><th>Invoice</th><th>Amount</th><th>Status</th></tr></thead><tbody>'+u.invoices.map(i=>`<tr><td>${esc(i.date)}</td><td>${esc(i.number)}</td><td>${money(i.amount)}</td><td>${esc(i.status)}</td></tr>`).join('')+'</tbody></table>':'<div class="empty-state" style="padding:30px"><div class="empty-icon">▣</div><h3>No invoices yet</h3><p>Paid invoices will appear here automatically.</p></div>'}</section>`;}
function settingsPage(){const tabs=[['profile','Profile'],['company','Company'],['password','Password'],['notifications','Notifications'],['billing','Subscription'],['delete','Delete account']];return `<div class="section-toolbar"><div><h2>Settings</h2><p>Manage your personal and company preferences.</p></div></div><div class="settings-layout"><nav class="glass-card settings-nav">${tabs.map(x=>`<button class="settings-link ${state.settingsTab===x[0]?'active':''}" data-settings="${x[0]}">${x[1]}</button>`).join('')}</nav><section class="glass-card settings-panel">${settingsContent()}</section></div>`;}
function settingsContent(){const u=state.session.user,d=u.onboarding?.data||{};if(state.settingsTab==='company')return `<h3>Company information</h3><p>Used across your workspace and AI context.</p><form id="company-form" class="settings-form">${inputField('Company name','companyName','text','Your company')}${inputField('Industry','industry','text','Agency')}${inputField('Website','website','url','https://yourcompany.com')}<div class="field"><label>Company size</label><select class="select" id="companySize"><option>Just me</option><option>2–10</option><option>11–50</option><option>51+</option></select></div><button class="btn btn-primary">Save company</button><div class="form-status" id="form-status"></div></form>`;
  if(state.settingsTab==='password')return `<h3>Password</h3><p>Use a strong, unique password for this customer account.</p><form id="password-form" class="settings-form">${inputField('Current password','currentPassword','password','Current password')}${inputField('New password','newPassword','password','10+ characters')}<button class="btn btn-primary">Update password</button><div class="form-status" id="form-status"></div></form>`;
  if(state.settingsTab==='notifications'){const p=u.preferences||{};return `<h3>Notifications</h3><p>Choose which customer workspace emails and alerts you receive.</p><div class="settings-form">${toggleRow('Product updates','New features and improvements','productUpdates',p.productUpdates)}${toggleRow('Activity alerts','Important workspace activity','activityAlerts',p.activityAlerts)}${toggleRow('Billing emails','Invoices and subscription notices','billingEmails',p.billingEmails)}${toggleRow('Weekly report','A concise performance summary','weeklyReport',p.weeklyReport)}<button class="btn btn-primary" id="save-notifications" style="margin-top:18px">Save preferences</button></div>`;}
  if(state.settingsTab==='billing')return `<h3>Subscription</h3><p>Plan changes are managed from the dedicated billing workspace.</p><div class="notice green">Current plan: <b>${plan(u.subscription?.plan).name}</b> · ${esc(u.subscription?.status||'active')}</div><a href="#billing" class="btn btn-primary" style="margin-top:17px">Open billing</a>`;
  if(state.settingsTab==='delete')return `<div class="danger-zone"><h3>Delete account</h3><p>Permanently removes this customer profile, onboarding data, and workspace settings. Your owner/admin dashboard is not affected.</p><form id="delete-form" class="settings-form">${inputField('Password','deletePassword','password','Confirm your password')}${inputField('Type DELETE','deleteConfirm','text','DELETE')}<button class="btn btn-danger">Permanently delete customer account</button><div class="form-status" id="form-status"></div></form></div>`;
  return `<h3>Profile</h3><p>Your personal information for this customer account.</p><form id="profile-form" class="settings-form"><div class="field-row">${inputField('First name','firstName','text','First name')}${inputField('Last name','lastName','text','Last name')}</div>${inputField('Job title','jobTitle','text','Founder')}<div class="field"><label>Email</label><input class="input" value="${esc(u.email)}" disabled></div><button class="btn btn-primary">Save profile</button><div class="form-status" id="form-status"></div></form>`;}
function toggleRow(title,desc,key,on){return `<div class="setting-row"><span><b>${title}</b><small>${desc}</small></span><button class="switch ${on?'active':''}" data-pref="${key}" aria-pressed="${on?'true':'false'}"><i></i></button></div>`;}

function setFormStatus(message,type=''){const el=document.getElementById('form-status');if(el){el.textContent=message;el.className='form-status '+type;}}
function formValue(id){return document.getElementById(id)?.value?.trim()||'';}

async function loadSession(){try{state.session=await api('/api/customer-data');}catch(error){if(error.message!=='Customer sign-in required')console.warn(error.message);state.session=null;const current=route();if(['/app','/welcome','/checkout'].some(path=>current===path||current.startsWith(path+'/'))){location.replace('/login?next='+encodeURIComponent(current+location.search+location.hash));return new Promise(()=>{});}}state.loading=false;}
function syncInputs(){const u=state.session?.user;if(!u)return;const values={firstName:u.firstName,lastName:u.lastName,jobTitle:u.jobTitle||'',companyName:u.company?.name||u.companyName||u.onboarding?.data?.companyName||'',industry:u.company?.industry||u.onboarding?.data?.industry||'',website:u.company?.website||u.onboarding?.data?.websiteUrl||''};Object.entries(values).forEach(([id,value])=>{const el=document.getElementById(id);if(el&&!el.value)el.value=value;});}

function bindCommon(){document.querySelectorAll('[data-password]').forEach(btn=>btn.addEventListener('click',()=>{const input=document.getElementById(btn.dataset.password);input.type=input.type==='password'?'text':'password';btn.textContent=input.type==='password'?'◉':'○';}));document.querySelectorAll('[data-interval]').forEach(btn=>btn.addEventListener('click',()=>{state.interval=btn.dataset.interval;localStorage.setItem('ascend-billing',state.interval);render();}));}
function bindAuth(){
  document.getElementById('login-form')?.addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;setBusy(btn,true,'Logging in…');try{const d=await api('/api/customer-auth',{method:'POST',body:JSON.stringify({action:'login',email:formValue('email'),password:formValue('password')})});location.href=d.redirect;}catch(err){setFormStatus(err.message,'error');if(err.code==='EMAIL_UNVERIFIED')setTimeout(()=>location.href='/verify-email?email='+encodeURIComponent(formValue('email')),900);setBusy(btn,false);}});
  document.getElementById('signup-form')?.addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;setBusy(btn,true,'Creating workspace…');try{const d=await api('/api/customer-auth',{method:'POST',body:JSON.stringify({action:'signup',firstName:formValue('firstName'),lastName:formValue('lastName'),email:formValue('email'),password:formValue('password')})});sessionStorage.setItem('ascend-pending-email',d.email);const p=qs('plan');if(p){sessionStorage.setItem('ascend-plan',p);sessionStorage.setItem('ascend-interval',qs('interval')||state.interval);}location.href='/verify-email'+(d.emailSent?'':'?delivery=failed');}catch(err){setFormStatus(err.message,'error');setBusy(btn,false);}});
  document.getElementById('forgot-form')?.addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;setBusy(btn,true,'Sending…');try{const d=await api('/api/customer-auth',{method:'POST',body:JSON.stringify({action:'forgot-password',email:formValue('email')})});setFormStatus(d.message,'success');}catch(err){setFormStatus(err.message,'error');}setBusy(btn,false);});
  document.getElementById('resend-form')?.addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;setBusy(btn,true,'Sending…');try{const d=await api('/api/customer-auth',{method:'POST',body:JSON.stringify({action:'resend-verification',email:formValue('email')})});setFormStatus(d.message,'success');}catch(err){setFormStatus(err.message,'error');}setBusy(btn,false);});
  document.getElementById('reset-form')?.addEventListener('submit',async e=>{e.preventDefault();if(formValue('password')!==formValue('confirmPassword')){setFormStatus('Passwords do not match','error');return;}const btn=e.submitter;setBusy(btn,true,'Updating…');try{const d=await api('/api/customer-auth',{method:'POST',body:JSON.stringify({action:'reset-password',token:qs('token'),password:formValue('password')})});location.href=d.redirect;}catch(err){setFormStatus(err.message,'error');setBusy(btn,false);}});
  const verify=document.getElementById('verify-state');if(verify&&qs('token'))api('/api/customer-auth',{method:'POST',body:JSON.stringify({action:'verify',token:qs('token')})}).then(d=>{verify.textContent='Email verified. Redirecting…';verify.className='form-status success';setTimeout(()=>location.href=d.redirect,500);}).catch(err=>{verify.textContent=err.message;verify.className='form-status error';});
  const email=document.getElementById('email');if(email&&!email.value)email.value=qs('email')||sessionStorage.getItem('ascend-pending-email')||'';
}

function collectOnboarding(){const step=state.onboardStep,d=state.onboardData,value=document.getElementById('onboard-value')?.value?.trim();if(step===1)d.companyName=value||'';if(step===2)d.industry=value||'';if(step===3)d.websiteUrl=value||'';if(step===4){d.primaryColor=document.getElementById('primaryColor').value;d.secondaryColor=document.getElementById('secondaryColor').value;}return d;}
async function saveOnboarding(completed=false){collectOnboarding();return api('/api/customer-data',{method:'POST',body:JSON.stringify({action:'save-onboarding',step:completed?8:Math.min(8,state.onboardStep+1),completed,...state.onboardData})});}
function bindOnboarding(){
  document.getElementById('onboard-back')?.addEventListener('click',()=>{state.onboardStep--;render();});
  document.getElementById('onboard-next')?.addEventListener('click',async e=>{const btn=e.currentTarget;setBusy(btn,true,'Saving…');try{if(state.onboardStep===1&&!formValue('onboard-value'))throw new Error('Enter your company name');if(state.onboardStep===2&&!formValue('onboard-value'))throw new Error('Choose an industry');await saveOnboarding(state.onboardStep===8);if(state.onboardStep===8){await api('/api/customer-data',{method:'POST',body:JSON.stringify({action:'finish-onboarding'})});location.href='/app';return;}state.onboardStep++;render();}catch(err){setFormStatus(err.message,'error');setBusy(btn,false);}});
  document.querySelectorAll('[data-goal]').forEach(btn=>btn.addEventListener('click',()=>{const arr=state.onboardData.goals||(state.onboardData.goals=[]),value=btn.dataset.goal,index=arr.indexOf(value);index>=0?arr.splice(index,1):arr.push(value);btn.classList.toggle('active');}));
  document.querySelectorAll('[data-social]').forEach(btn=>btn.addEventListener('click',()=>{const arr=state.onboardData.socials||(state.onboardData.socials=[]),value=btn.dataset.social,index=arr.indexOf(value);index>=0?arr.splice(index,1):arr.push(value);btn.classList.toggle('active');}));
  document.getElementById('logo-upload')?.addEventListener('change',e=>{const file=e.target.files?.[0];if(!file)return;if(file.size>350000){setFormStatus('Use a logo under 350 KB','error');return;}const reader=new FileReader();reader.onload=()=>{state.onboardData.logoData=reader.result;render();};reader.readAsDataURL(file);});
}

function bindCheckout(){document.getElementById('activate-plan')?.addEventListener('click',async e=>{const btn=e.currentTarget,data=selectedCheckout();setBusy(btn,true,'Starting trial…');try{const result=await api('/api/customer-billing',{method:'POST',body:JSON.stringify({action:'activate-demo',plan:data.chosen.id,interval:data.interval})});await loadSession();location.href=result.redirect;}catch(err){setFormStatus(err.message,'error');setBusy(btn,false);}});}
function bindWorkspace(){
  const run=async(button,payload,label)=>{setBusy(button,true,label);try{await api('/api/customer-workspace',{method:'POST',body:JSON.stringify(payload)});await loadSession();render();toast('Saved to your workspace','success');}catch(err){toast(err.message,'error');setBusy(button,false);}};
  document.querySelectorAll('[data-workspace-action]').forEach(button=>button.addEventListener('click',async()=>{const action=button.dataset.workspaceAction;
    if(action==='website'){const name=prompt('What do you want to call this website?');if(!name)return;const url=prompt('What is its current domain? (optional)')||'';await run(button,{action:'create-website',name,url},'Creating…');}
    if(action==='content'){const topic=prompt('What should Ascend write about?');if(!topic)return;await run(button,{action:'generate-content',topic},'Generating…');}
    if(action==='social'){const text=prompt('Enter the post copy to save as a draft.');if(!text)return;await run(button,{action:'create-social-draft',text},'Saving…');}
    if(action==='campaign'){const name=prompt('Campaign name');if(!name)return;const objective=prompt('What is the campaign objective?')||'';await run(button,{action:'create-campaign',name,objective},'Creating…');}
  }));
  document.getElementById('assistant-form')?.addEventListener('submit',async e=>{e.preventDefault();const button=e.submitter,promptText=formValue('assistant-prompt');if(!promptText){setFormStatus('Ask Ascend a question first.','error');return;}setBusy(button,true,'Thinking…');try{await api('/api/customer-workspace',{method:'POST',body:JSON.stringify({action:'ask-assistant',prompt:promptText})});await loadSession();render();}catch(err){setFormStatus(err.message,'error');setBusy(button,false);}});
}
function notificationValues(){const out={};document.querySelectorAll('[data-pref]').forEach(btn=>out[btn.dataset.pref]=btn.classList.contains('active'));return out;}
function bindApp(){
  document.getElementById('mobile-menu')?.addEventListener('click',()=>{state.mobileMenu=!state.mobileMenu;document.getElementById('customer-shell')?.classList.toggle('menu-open',state.mobileMenu);});
  document.getElementById('logout-btn')?.addEventListener('click',async()=>{await api('/api/customer-auth',{method:'POST',body:JSON.stringify({action:'logout'})});location.href='/login';});
  document.querySelectorAll('[data-settings]').forEach(btn=>btn.addEventListener('click',()=>{state.settingsTab=btn.dataset.settings;render();}));
  document.querySelectorAll('[data-pref]').forEach(btn=>btn.addEventListener('click',()=>btn.classList.toggle('active')));
  document.getElementById('save-notifications')?.addEventListener('click',async e=>{setBusy(e.currentTarget,true,'Saving…');try{await api('/api/customer-data',{method:'POST',body:JSON.stringify({action:'update-notifications',...notificationValues()})});toast('Notification preferences saved');await loadSession();render();}catch(err){toast(err.message,'error');setBusy(e.currentTarget,false);}});
  document.getElementById('profile-form')?.addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;setBusy(btn,true,'Saving…');try{await api('/api/customer-data',{method:'POST',body:JSON.stringify({action:'update-profile',firstName:formValue('firstName'),lastName:formValue('lastName'),jobTitle:formValue('jobTitle')})});toast('Profile updated');await loadSession();render();}catch(err){setFormStatus(err.message,'error');setBusy(btn,false);}});
  document.getElementById('company-form')?.addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;setBusy(btn,true,'Saving…');try{await api('/api/customer-data',{method:'POST',body:JSON.stringify({action:'update-company',name:formValue('companyName'),industry:formValue('industry'),website:formValue('website'),size:document.getElementById('companySize')?.value,timezone:Intl.DateTimeFormat().resolvedOptions().timeZone})});toast('Company information saved');await loadSession();render();}catch(err){setFormStatus(err.message,'error');setBusy(btn,false);}});
  document.getElementById('password-form')?.addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;setBusy(btn,true,'Updating…');try{await api('/api/customer-data',{method:'POST',body:JSON.stringify({action:'change-password',currentPassword:formValue('currentPassword'),newPassword:formValue('newPassword')})});setFormStatus('Password updated','success');e.target.reset();}catch(err){setFormStatus(err.message,'error');}setBusy(btn,false);});
  document.getElementById('delete-form')?.addEventListener('submit',async e=>{e.preventDefault();if(!confirm('Permanently delete this customer account? This cannot be undone.'))return;const btn=e.submitter;setBusy(btn,true,'Deleting…');try{const d=await api('/api/customer-data',{method:'POST',body:JSON.stringify({action:'delete-account',password:formValue('deletePassword'),confirm:formValue('deleteConfirm')})});location.href=d.redirect;}catch(err){setFormStatus(err.message,'error');setBusy(btn,false);}});
  document.querySelectorAll('[data-billing]').forEach(btn=>btn.addEventListener('click',async()=>{const action=btn.dataset.billing;if(action==='cancel'&&!confirm('Cancel at the end of the current period?'))return;try{await api('/api/customer-billing',{method:'POST',body:JSON.stringify({action})});toast(action==='cancel'?'Cancellation scheduled':'Subscription resumed');await loadSession();render();}catch(err){toast(err.message,'error');}}));
  syncInputs();bindWorkspace();
}

function render(){const r=route();let html;if(r==='/')html=renderLanding();else if(r==='/login')html=renderLogin();else if(r==='/signup')html=renderSignup();else if(r==='/forgot-password')html=renderForgot();else if(r==='/verify-email')html=renderVerify();else if(r==='/reset-password')html=renderReset();else if(r==='/pricing')html=renderPricing();else if(r==='/welcome')html=renderWelcome();else if(r==='/checkout')html=renderCheckout();else if(r==='/checkout/payment')html=renderPayment();else if(r==='/checkout/success')html=renderSuccess();else if(r==='/app'||r.startsWith('/app/'))html=appShell();else html=renderLanding();root.innerHTML=html;bindCommon();bindAuth();bindOnboarding();bindCheckout();bindApp();}

window.addEventListener('hashchange',()=>{state.mobileMenu=false;render();});
loadSession().then(render);
